sp_widget.client_script:
api.controller = function(spUtil) {
  var c = this;

  c.showEditView = false;
  c.selectedPatient = {};

  // Pagination & Filter variables
  c.searchText = '';
  c.filterState = '';
  c.currentPage = 1;
  c.pageSize = 5; 
  c.filteredPatients = [];
  c.totalPages = 1;

  // The Local Search & Filter Engine
  c.updateFilters = function() {
    c.filteredPatients = c.data.myPatients.filter(function(p) {

      var matchText = true;
      if (c.searchText) {
        var term = c.searchText.toLowerCase();
        var nameMatch = p.full_name && p.full_name.toLowerCase().indexOf(term) !== -1;
        var numMatch = p.number && p.number.toLowerCase().indexOf(term) !== -1;
        matchText = nameMatch || numMatch;
      }

      var matchState = true;
      if (c.filterState) {
        matchState = (p.state === c.filterState);
      }

      return matchText && matchState;
    });

    c.totalPages = Math.ceil(c.filteredPatients.length / c.pageSize) || 1;

    if (c.currentPage > c.totalPages) {
      c.currentPage = c.totalPages > 0 ? c.totalPages : 1;
    }
  };

  // --- NEW: Dynamic Numbered Pagination Logic ---
  c.getPageArray = function() {
    var pages = [];
    for (var i = 1; i <= c.totalPages; i++) {
      pages.push(i);
    }
    return pages;
  };

  c.goToPage = function(pageNum) {
    c.currentPage = pageNum;
  };

  c.prevPage = function() {
    if (c.currentPage > 1) { c.currentPage--; }
  };

  c.nextPage = function() {
    if (c.currentPage < c.totalPages) { c.currentPage++; }
  };

  c.clearFilters = function() {
    c.searchText = '';
    c.filterState = '';
    c.updateFilters();
  };

  c.updateFilters();

  // Open Edit View & Fetch Native Form
  c.selectPatient = function(patient) {
    c.selectedPatient = patient; 
    c.showEditView = true; 

    spUtil.get('widget-form', {
      table: 'x_1954503_smartc_0_patient',
      sys_id: patient.sys_id,
      view: 'default', 
      hideRelatedLists: true 
    }).then(function(response) {
      c.embeddedForm = response; 
    });
  };

  // Cancel and return to List
  c.backToList = function() {
    c.selectedPatient = {};
    c.embeddedForm = null; 
    c.showEditView = false; 

    c.server.update().then(function() {
        c.updateFilters(); 
    });
  };
};

sp_widget.css:
/* --- Global Wrapper & Typography --- */
.sc-doc-wrapper {
  font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  color: #1e293b;
  background-color: #f8fafc;
  padding: 30px;
}

.sc-doc-panel {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  margin-bottom: 24px;
  overflow: hidden;
  border: 1px solid #eef2f6;
}

.sc-doc-panel-header {
  padding: 20px 24px;
  border-bottom: 1px solid #f1f5f9;
  background-color: #ffffff;
}

.sc-doc-panel-title { margin: 0; font-size: 18px; font-weight: 600;}
.sc-doc-flex-between { display: flex; justify-content: space-between; align-items: center;}

/* --- Filters Styling --- */
.sc-doc-filter-bar {
  display: flex;
  gap: 16px;
  padding: 16px 24px;
  background-color: #fcfdfe;
  border-bottom: 1px solid #f1f5f9;
}

.sc-doc-filter-input, .sc-doc-filter-select {
  height: 38px;
  border: 1px solid #e2e8f0;
  border-radius: 6px;
  padding: 6px 12px;
  font-size: 13px;
  outline: none;
  color: #1e293b;
}

.sc-doc-filter-input:focus, .sc-doc-filter-select:focus {
  border-color: #0052cc;
  box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.1);
}

.sc-doc-filter-input { flex: 1; max-width: 350px; }
.sc-doc-filter-select { width: 180px; }

/* --- NUMBERED PAGINATION STYLING --- */
.sc-doc-pagination {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  background-color: #ffffff;
  border-top: 1px solid #f1f5f9;
}

.sc-doc-page-numbers {
  display: flex;
  gap: 6px;
}

.sc-doc-btn-page, .sc-doc-btn-page-num {
  background: #ffffff;
  border: 1px solid #e2e8f0;
  color: #475569;
  padding: 6px 12px;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
}

.sc-doc-btn-page-num {
  padding: 6px 14px; /* Slightly wider for numbers */
}

.sc-doc-btn-page:hover:not([disabled]), .sc-doc-btn-page-num:hover {
  background: #f1f5f9;
  border-color: #cbd5e1;
}

.sc-doc-btn-page[disabled] {
  opacity: 0.5;
  cursor: not-allowed;
}

.sc-doc-btn-page-num.active {
  background: #0052cc;
  color: #ffffff;
  border-color: #0052cc;
}

.sc-doc-empty-status { padding: 40px 20px; text-align: center; color: #64748b; }

/* --- 1. TABLE BEAUTIFICATION --- */
.sc-doc-table { width: 100%; border-collapse: collapse; }
.sc-doc-table th { background-color: #f8fafc; color: #64748b; font-size: 11px; font-weight: 700; text-transform: uppercase; padding: 16px 24px; border-bottom: 2px solid #f1f5f9; text-align: left;}
.sc-doc-table td { padding: 18px 24px; border-bottom: 1px solid #f1f5f9; font-size: 14px; }
.sc-doc-table tbody tr:hover { background-color: #fcfdfe; }

.sc-doc-text-critical, .sc-doc-text-high, .sc-doc-text-moderate, .sc-doc-text-low { padding: 4px 12px; border-radius: 20px; font-size: 11px; font-weight: 700; display: inline-block; text-transform: uppercase; }
.sc-doc-text-critical { background-color: #fee2e2; color: #b91c1c; }
.sc-doc-text-high { background-color: #ffedd5; color: #9a3412; }
.sc-doc-text-moderate { background-color: #dbeafe; color: #1e40af; }
.sc-doc-text-low { background-color: #dcfce7; color: #15803d; }
.sc-doc-fw-bold { font-weight: 600; }
.sc-doc-text-capitalize { text-transform: capitalize; }

/* --- 2. REFERENCE FIELD FIX --- */
.sc-doc-wrapper .form-control,
.sc-doc-wrapper input,
.sc-doc-wrapper select {
  height: 38px !important; 
  border: 1px solid #e2e8f0 !important;
  border-radius: 6px !important;
  padding: 6px 12px !important;
  box-shadow: none !important;
  font-size: 13px !important;
}

.sc-doc-wrapper .input-group {
  display: flex !important;
  width: 100% !important;
  border: 1px solid #e2e8f0 !important; 
  border-radius: 6px !important;
  overflow: hidden !important;
  background: #fff !important;
}

.sc-doc-wrapper .input-group .form-control {
  border: none !important; 
  margin: 0 !important;
  flex: 1 1 auto !important;
}

.sc-doc-wrapper .input-group-btn {
  display: flex !important;
  background-color: #f8fafc !important;
  border: none !important;
  padding: 0 !important;
  margin: 0 !important;
}

.sc-doc-wrapper .input-group-btn .btn {
  border: none !important;
  background: transparent !important;
  height: 38px !important;
  padding: 0 12px !important;
  color: #64748b !important;
  box-shadow: none !important;
}

.sc-doc-wrapper .input-group-btn:last-child {
  border-left: 1px solid #f1f5f9 !important;
}

.sc-doc-wrapper .input-group:hover {
  border-color: #cbd5e1 !important;
}

.sc-doc-wrapper .input-group:focus-within {
  border-color: #0052cc !important;
  box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.1) !important;
}

/* --- 3. SPACING & BUTTONS --- */
.sc-doc-panel-body { padding: 24px; }

.sc-doc-info-grid {
  display: flex; gap: 40px; background: #f1f5f9; padding: 15px 20px; border-radius: 8px; margin-bottom: 25px;
}

.sc-doc-wrapper label {
  font-weight: 600 !important; color: #475569 !important; font-size: 12px !important; margin-bottom: 6px !important;
}

.sc-doc-btn-link, .sc-doc-wrapper .btn-primary {
  background: #0052cc !important; border: none !important; color: #fff !important;
  padding: 8px 16px !important; border-radius: 6px !important; font-weight: 600 !important; cursor: pointer;
}

.sc-doc-btn-default, .sc-doc-wrapper .btn-default {
  background: #fff !important; border: 1px solid #e2e8f0 !important; color: #64748b !important;
  padding: 8px 16px !important; border-radius: 6px !important; font-weight: 600; cursor: pointer;
}

.sc-doc-btn-default[disabled] {
  opacity: 0.5;
  cursor: not-allowed;
}

sp_widget.script:
(function() {
    var userId = gs.getUserID();

    var isDoctor = gs.hasRole('x_1954503_smartc_0.doctor');
    var isNurse = gs.hasRole('x_1954503_smartc_0.nurse');

    data.myPatients = [];
    var pGR = new GlideRecord('x_1954503_smartc_0_patient');

    if (isDoctor) {
        pGR.addQuery('assigned_doctor', userId);
    } else if (isNurse) {
        pGR.addQuery('u_assigned_nurse', userId); 
    } else {
        if (!gs.hasRole('admin')) {
            return; 
        }
    }

    pGR.orderByDesc('sys_created_on');
    pGR.query();

    while (pGR.next()) {
        data.myPatients.push({
            sys_id: pGR.getUniqueValue(),
            number: pGR.getValue('number') || 'N/A', 
            full_name: pGR.getValue('full_name') || 'Unknown',
            age: pGR.getValue('age') || '',
            department: pGR.getDisplayValue('medical_department') || '',
            state: pGR.getValue('state') || 'waiting',
            severity: pGR.getValue('severity') || 'low',
            symptoms: pGR.getValue('symptoms') || '',

            assigned_doctor: pGR.getDisplayValue('assigned_doctor'),
            assigned_nurse: pGR.getDisplayValue('assigned_nurse')
        });
    }
})();
